package main

import (
	"errors"
	"fmt"
	"sync"
)

var (
	ErrAccountNotFound    = errors.New("account not found")
	ErrInsufficientFunds  = errors.New("insufficient funds")
	ErrNegativeAmount     = errors.New("amount must be positive")
	ErrAccountExists      = errors.New("account already exists")
	ErrSameAccount        = errors.New("cannot transfer to the same account")
)

// Bank holds all accounts and provides thread-safe operations.
type Bank struct {
	mu       sync.RWMutex
	accounts map[string]*Account
}

// Account represents a single bank account with its own mutex for fine-grained locking.
type Account struct {
	mu      sync.Mutex
	id      string
	balance float64
}

// TransactionResult represents the outcome of a transaction.
type TransactionResult struct {
	AccountID  string
	OldBalance float64
	NewBalance float64
	Amount     float64
	Type       string
	Success    bool
	Error      error
}

// NewBank creates a new Bank instance.
func NewBank() *Bank {
	return &Bank{
		accounts: make(map[string]*Account),
	}
}

// CreateAccount creates a new account with an initial balance.
func (b *Bank) CreateAccount(id string, initialBalance float64) error {
	if initialBalance < 0 {
		return ErrNegativeAmount
	}

	b.mu.Lock()
	defer b.mu.Unlock()

	if _, exists := b.accounts[id]; exists {
		return ErrAccountExists
	}

	b.accounts[id] = &Account{
		id:      id,
		balance: initialBalance,
	}
	return nil
}

// getAccount retrieves an account while holding at least a read lock on the bank.
func (b *Bank) getAccount(id string) (*Account, error) {
	b.mu.RLock()
	acc, exists := b.accounts[id]
	b.mu.RUnlock()
	if !exists {
		return nil, ErrAccountNotFound
	}
	return acc, nil
}

// GetBalance returns the current balance of an account.
func (b *Bank) GetBalance(id string) (float64, error) {
	acc, err := b.getAccount(id)
	if err != nil {
		return 0, err
	}

	acc.mu.Lock()
	defer acc.mu.Unlock()
	return acc.balance, nil
}

// Deposit adds funds to an account atomically.
// The balance check and update happen within a single locked section.
func (b *Bank) Deposit(id string, amount float64) (*TransactionResult, error) {
	if amount <= 0 {
		return nil, ErrNegativeAmount
	}

	acc, err := b.getAccount(id)
	if err != nil {
		return nil, err
	}

	// Lock the account — the read-modify-write is fully protected.
	acc.mu.Lock()
	defer acc.mu.Unlock()

	oldBalance := acc.balance
	acc.balance += amount

	return &TransactionResult{
		AccountID:  id,
		OldBalance: oldBalance,
		NewBalance: acc.balance,
		Amount:     amount,
		Type:       "deposit",
		Success:    true,
	}, nil
}

// Withdraw removes funds from an account atomically.
// The sufficiency check and balance update are performed in one locked section,
// preventing double-spend / TOCTOU races.
func (b *Bank) Withdraw(id string, amount float64) (*TransactionResult, error) {
	if amount <= 0 {
		return nil, ErrNegativeAmount
	}

	acc, err := b.getAccount(id)
	if err != nil {
		return nil, err
	}

	// Lock the account — check-and-update is atomic.
	acc.mu.Lock()
	defer acc.mu.Unlock()

	if acc.balance < amount {
		return &TransactionResult{
			AccountID:  id,
			OldBalance: acc.balance,
			NewBalance: acc.balance,
			Amount:     amount,
			Type:       "withdrawal",
			Success:    false,
			Error:      ErrInsufficientFunds,
		}, ErrInsufficientFunds
	}

	oldBalance := acc.balance
	acc.balance -= amount

	return &TransactionResult{
		AccountID:  id,
		OldBalance: oldBalance,
		NewBalance: acc.balance,
		Amount:     amount,
		Type:       "withdrawal",
		Success:    true,
	}, nil
}

// Transfer moves funds between two accounts atomically.
// Both accounts are locked in a consistent order (lexicographic by ID)
// to prevent deadlocks, and the balance check + updates happen inside
// the critical section so no double-spend is possible.
func (b *Bank) Transfer(fromID, toID string, amount float64) (*TransactionResult, error) {
	if amount <= 0 {
		return nil, ErrNegativeAmount
	}
	if fromID == toID {
		return nil, ErrSameAccount
	}

	fromAcc, err := b.getAccount(fromID)
	if err != nil {
		return nil, fmt.Errorf("source account: %w", err)
	}
	toAcc, err := b.getAccount(toID)
	if err != nil {
		return nil, fmt.Errorf("destination account: %w", err)
	}

	// Always lock in consistent (lexicographic) order to avoid deadlocks.
	first, second := fromAcc, toAcc
	if fromID > toID {
		first, second = toAcc, fromAcc
	}

	first.mu.Lock()
	defer first.mu.Unlock()
	second.mu.Lock()
	defer second.mu.Unlock()

	// Check-and-update is fully atomic under both locks.
	if fromAcc.balance < amount {
		return &TransactionResult{
			AccountID:  fromID,
			OldBalance: fromAcc.balance,
			NewBalance: fromAcc.balance,
			Amount:     amount,
			Type:       "transfer",
			Success:    false,
			Error:      ErrInsufficientFunds,
		}, ErrInsufficientFunds
	}

	oldBalance := fromAcc.balance
	fromAcc.balance -= amount
	toAcc.balance += amount

	return &TransactionResult{
		AccountID:  fromID,
		OldBalance: oldBalance,
		NewBalance: fromAcc.balance,
		Amount:     amount,
		Type:       "transfer",
		Success:    true,
	}, nil
}

func main() {
	bank := NewBank()

	// Create accounts
	accounts := []struct {
		id      string
		balance float64
	}{
		{"alice", 1000.0},
		{"bob", 500.0},
		{"charlie", 750.0},
	}

	for _, a := range accounts {
		if err := bank.CreateAccount(a.id, a.balance); err != nil {
			fmt.Printf("Error creating account %s: %v\n", a.id, err)
			return
		}
	}

	fmt.Println("=== Initial Balances ===")
	for _, a := range accounts {
		bal, _ := bank.GetBalance(a.id)
		fmt.Printf("  %s: $%.2f\n", a.id, bal)
	}

	// Run concurrent transactions
	var wg sync.WaitGroup

	// Simulate many concurrent deposits
	for i := 0; i < 100; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			bank.Deposit("alice", 10.0)
		}()
	}

	// Simulate many concurrent withdrawals
	for i := 0; i < 50; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			bank.Withdraw("bob", 5.0)
		}()
	}

	// Simulate many concurrent transfers
	for i := 0; i < 100; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			bank.Transfer("alice", "charlie", 5.0)
		}()
	}

	// Simulate concurrent transfers in the opposite direction to stress deadlock prevention
	for i := 0; i < 50; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			bank.Transfer("charlie", "alice", 3.0)
		}()
	}

	wg.Wait()

	fmt.Println("\n=== Final Balances ===")
	totalBefore := 0.0
	totalAfter := 0.0
	for _, a := range accounts {
		totalBefore += a.balance
		bal, _ := bank.GetBalance(a.id)
		totalAfter += bal
		fmt.Printf("  %s: $%.2f\n", a.id, bal)
	}

	fmt.Printf("\n=== Consistency Check ===\n")
	fmt.Printf("  Total before: $%.2f\n", totalBefore)
	fmt.Printf("  Total after:  $%.2f\n", totalAfter)
	if totalBefore == totalAfter {
		fmt.Println("  ✓ Money is conserved — no double-spend detected.")
	} else {
		fmt.Println("  ✗ INCONSISTENCY DETECTED!")
	}

	// Demonstrate error handling
	fmt.Println("\n=== Error Handling ===")

	_, err := bank.Withdraw("bob", 999999.0)
	fmt.Printf("  Large withdrawal from bob: %v\n", err)

	_, err = bank.Deposit("nonexistent", 100.0)
	fmt.Printf("  Deposit to nonexistent: %v\n", err)

	_, err = bank.Transfer("alice", "alice", 10.0)
	fmt.Printf("  Self-transfer: %v\n", err)

	_, err = bank.Deposit("alice", -50.0)
	fmt.Printf("  Negative deposit: %v\n", err)
}